import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider } from './contexts/AuthContext';

// Pages
import HomePage from './pages/HomePage';
import Dashboard from './pages/Dashboard';
import HistoryPage from './pages/HistoryPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import SchemesPage from './pages/SchemesPage';
import WeatherPage from './pages/WeatherPage';

// Components
import Navbar from './components/Navbar';
import ImageUpload from './components/ImageUpload';
import WeatherRiskCard from './components/WeatherRiskCard';
import SchemeCard from './components/SchemeCard';
import MapView from './components/MapView';
import PrivateRoute from './components/PrivateRoute';

// Styles
import './App.css';

function App() {
  return (
    <AuthProvider>
      <Router>
        <div className="min-h-screen bg-gray-50">
          <Navbar />
          <main className="container mx-auto px-4 py-8">
            <Routes>
              {/* Public routes */}
              <Route path="/" element={<HomePage />} />
              <Route path="/login" element={<LoginPage />} />
              <Route path="/register" element={<RegisterPage />} />
              
              {/* Detection route (public or protected based on your preference) */}
              <Route path="/detect" element={<ImageUpload />} />
              
              {/* Map route (public) */}
              <Route path="/map" element={<MapView />} />
              
              {/* Protected routes */}
              <Route path="/dashboard" element={
                <PrivateRoute>
                  <Dashboard />
                </PrivateRoute>
              } />
              <Route path="/history" element={
                <PrivateRoute>
                  <HistoryPage />
                </PrivateRoute>
              } />
              <Route path="/schemes" element={
                <PrivateRoute>
                  <SchemesPage />
                </PrivateRoute>
              } />
              <Route path="/weather" element={
                <PrivateRoute>
                  <WeatherPage />
                </PrivateRoute>
              } />
              
              {/* Component routes (can also be protected if needed) */}
              <Route path="/weather-card" element={<WeatherRiskCard />} />
              <Route path="/scheme-card" element={<SchemeCard />} />
              
              {/* Redirect to home if route not found */}
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </main>
          <Toaster 
            position="top-right"
            toastOptions={{
              duration: 4000,
              style: {
                background: '#363636',
                color: '#fff',
              },
              success: {
                duration: 3000,
                iconTheme: {
                  primary: '#10b981',
                  secondary: '#fff',
                },
              },
              error: {
                duration: 4000,
                iconTheme: {
                  primary: '#ef4444',
                  secondary: '#fff',
                },
              },
            }}
          />
        </div>
      </Router>
    </AuthProvider>
  );
}

export default App;
